const spreadsheet = $input.first().json;

// Find Fees Closed tab — exact match only to avoid picking up unrelated tabs
const sheet = spreadsheet.sheets?.find(s =>
  s.properties?.title?.trim().toLowerCase() === 'fees closed',
);

if (!sheet?.data?.[0]?.rowData) {
  throw new Error(
    'Fees Closed tab not found. Check that the sheet has a tab named "Fees Closed".',
  );
}

const rowData = sheet.data[0].rowData;
if (rowData.length < 2) return [{ json: { rows: [] } }];

// Map header names → column indices (case-insensitive)
const headerRow = rowData[0].values ?? [];
const headers = headerRow.map(cell =>
  (cell.formattedValue ?? cell.effectiveValue?.stringValue ?? '').trim(),
);
const idx = name =>
  headers.findIndex(h => h.toLowerCase() === name.toLowerCase());

const C = {
  date:             idx('date'),
  caseName:         idx('CASE NAME'),
  assignedTo:       idx('ASSIGNED TO'),
  caseLevel:        idx('CASE LEVEL'),
  claimType:        idx('CLAIM TYPE'),
  approvalDate:     idx('APPROVAL DATE'),
  winSheet:         idx('WIN SHEET'),
  winSheetLink:     idx('WIN SHEET LINK'),
  feesConf:         idx('FEES CONFIRMATION'),
  caseStatus:       idx('CASE STATUS'),
  approvedBy:       idx('APPROVED BY (OK TO CLOSE)'),
  t16Retro:         idx('T16 RETRO'),
  t16FeeDue:        idx('T16 FEE DUE'),
  t16FeeRcv:        idx("T16 FEE $ REC'D"),
  t16Pending:       idx('T16 Pending'),
  t16Date:          idx("DATE T16 FEE REC'D"),
  t2Retro:          idx('T2 RETRO'),
  t2FeeDue:         idx('T2 FEE DUE'),
  t2FeeRcv:         idx("T2 FEE $ REC'D"),
  t2Pending:        idx('T2 Pending'),
  t2Date:           idx("DATE T2 FEE REC'D"),
  auxRetro:         idx('RETRO AUX'),
  auxFeeDue:        idx('AUX FEE DUE'),
  auxFeeRcv:        idx("AUX FEE $ REC'D"),
  auxPending:       idx('AUX PENDING'),
  auxDate:          idx("DATE AUX FEE REC'D"),
  totalRetroDue:    idx('TOTAL RETRO DUE'),
  totalFeesExp:     idx('TOTAL FEES EXPECTED'),
  totalFeesPaid:    idx('TOTAL FEES PAID'),
  recentUpdates:    idx('RECENT STATUS UPDATES'),
};

const getCell = (row, colIdx) =>
  colIdx >= 0 ? (row.values?.[colIdx] ?? null) : null;

const val = (row, colIdx) => {
  const cell = getCell(row, colIdx);
  return cell?.formattedValue ?? cell?.effectiveValue?.stringValue ?? null;
};

const link = (row, colIdx) =>
  getCell(row, colIdx)?.hyperlink ?? null;

const num = (row, colIdx) => {
  const cell = getCell(row, colIdx);
  if (!cell) return null;
  if (cell.effectiveValue?.numberValue !== undefined)
    return cell.effectiveValue.numberValue;
  const s = (cell.formattedValue ?? '').replace(/[,$\s]/g, '');
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
};

const rows = [];
for (let i = 1; i < rowData.length; i++) {
  const row = rowData[i];
  const caseNameText = val(row, C.caseName);
  if (!caseNameText?.trim()) continue;

  rows.push({
    'date':                       val(row, C.date),
    'CASE NAME':                  caseNameText,
    'ASSIGNED TO':                val(row, C.assignedTo),
    'CASE LEVEL':                 val(row, C.caseLevel),
    'CLAIM TYPE':                 val(row, C.claimType),
    'APPROVAL DATE':              val(row, C.approvalDate),
    'WIN SHEET':                  val(row, C.winSheet),
    'WIN SHEET LINK':             val(row, C.winSheetLink),
    'WIN SHEET LINK_url':         link(row, C.winSheetLink),
    'FEES CONFIRMATION':          val(row, C.feesConf),
    'CASE STATUS':                val(row, C.caseStatus),
    'APPROVED BY (OK TO CLOSE)':  val(row, C.approvedBy),
    'T16 RETRO':                  num(row, C.t16Retro),
    'T16 FEE DUE':                num(row, C.t16FeeDue),
    "T16 FEE $ REC'D":            num(row, C.t16FeeRcv),
    'T16 Pending':                num(row, C.t16Pending),
    "DATE T16 FEE REC'D":         val(row, C.t16Date),
    'T2 RETRO':                   num(row, C.t2Retro),
    'T2 FEE DUE':                 num(row, C.t2FeeDue),
    "T2 FEE $ REC'D":             num(row, C.t2FeeRcv),
    'T2 Pending':                 num(row, C.t2Pending),
    "DATE T2 FEE REC'D":          val(row, C.t2Date),
    'RETRO AUX':                  num(row, C.auxRetro),
    'AUX FEE DUE':                num(row, C.auxFeeDue),
    "AUX FEE $ REC'D":            num(row, C.auxFeeRcv),
    'AUX PENDING':                num(row, C.auxPending),
    "DATE AUX FEE REC'D":         val(row, C.auxDate),
    'TOTAL RETRO DUE':            num(row, C.totalRetroDue),
    'TOTAL FEES EXPECTED':        num(row, C.totalFeesExp),
    'TOTAL FEES PAID':            num(row, C.totalFeesPaid),
    'RECENT STATUS UPDATES':      val(row, C.recentUpdates),
  });
}

return [{ json: { rows } }];
